# Category: broken_access_control

from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Assume user data is stored in a dictionary (in a real app you'd use a database)
users = {
    1: {"email": "admin@example.com", "username": "admin", "role": "admin", "account_status": "active",
        "subscription_tier": "pro"},
}

current_user_id = 1

# User model
class User:
    def __init__(self, user_data):
        self.id = user_data["id"]
        self.email = user_data["email"]
        self.username = user_data["username"]
        self.role = user_data["role"]
        self.account_status = user_data["account_status"]
        self.subscription_tier = user_data["subscription_tier"]

    def to_dict(self):
        return {
            "id": self.id,
            "email": self.email,
            "username": self.username,
            "role": self.role,
            "account_status": self.account_status,
            "subscription_tier": self.subscription_tier
        }

# PUT /api/users/<user_id>
@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    data = request.json
    user = User(users[user_id])

    if current_user_id != 1 and current_user_id != user_id:
        return jsonify({"error": "Unauthorized"}), 401

    if 'email' in data:
        user.email = data['email']
    if 'username' in data:
        user.username = data['username']
    if 'role' in data:
        if data['role'] not in ['user', 'moderator', 'admin']:
            return jsonify({"error": "Invalid role"}), 400
        user.role = data['role']
    if 'account_status' in data:
        if data['account_status'] not in ['active', 'suspended']:
            return jsonify({"error": "Invalid account status"}), 400
        user.account_status = data['account_status']
    if 'subscription_tier' in data:
        if data['subscription_tier'] not in ['free', 'pro', 'enterprise']:
            return jsonify({"error": "Invalid subscription tier"}), 400
        user.subscription_tier = data['subscription_tier']

    users[user_id] = {
        "id": user.id,
        "email": user.email,
        "username": user.username,
        "role": user.role,
        "account_status": user.account_status,
        "subscription_tier": user.subscription_tier
    }

    return jsonify(user.to_dict()), 200

